<pre><code data-type="javascript">const store = document.getElementById('app')._reactRootContainer._internalRoot.current.memoizedState.element.props.store

function select(state) {
  return state.some.deep.property
}

let currentValue
function handleChange() {
  let previousValue = currentValue
  currentValue = select(store.getState())
  if (previousValue !== currentValue) {
    console.log(
      'Some deep nested property changed from',
      previousValue,
      'to',
      currentValue
    )
  }
}
const unsubscribe = store.subscribe(handleChange)</code></pre>
